import{_ as e,o as d,c as o,ai as a}from"./chunks/framework.rV0OLpih.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"posts/containerd/k8s/pv-pvc.md","filePath":"posts/containerd/k8s/pv-pvc.md"}'),r={name:"posts/containerd/k8s/pv-pvc.md"};function s(l,t,p,n,c,i){return d(),o("div",null,[...t[0]||(t[0]=[a('<h3 id="pv-pvc" tabindex="-1">PV &amp;&amp; PVC <a class="header-anchor" href="#pv-pvc" aria-label="Permalink to “PV &amp;&amp; PVC”">​</a></h3><ul><li><strong>PV（PersistentVolume，持久卷</strong></li></ul><blockquote><p><code>PV 是集群中的一块存储资源。它类似于一个节点(Node)是集群的计算资源一样，PV 是集群的存储资源</code></p></blockquote><ul><li><strong>PVC（PersistentVolumeClaim，持久卷声明）</strong></li></ul><blockquote><p><code>PVC 是用户（通常是应用部署者）对存储资源的请求（Claim）。它类似于 Pod 消耗节点资源一样，PVC 消耗 PV 资源</code></p></blockquote><ul><li><strong>PV &amp;&amp; PVC 区别</strong></li></ul><table tabindex="0"><thead><tr><th>名称</th><th>PV</th><th>PVC</th></tr></thead><tbody><tr><td>角色</td><td>资源提供者</td><td>资源请求者</td></tr><tr><td>管理者</td><td>通常由集群管理员维护</td><td>通常由应用开发者/用户维护</td></tr><tr><td>生命周期</td><td>独立于 Pod，属于集群层级的资源</td><td>依赖于应用，属于命名空间层级的资源</td></tr><tr><td>关注点</td><td>关注底层存储的实现细节（如服务器IP、驱动、认证）</td><td>关注应用的需求（如多少空间、读写速度）</td></tr><tr><td>层级</td><td>集群级别（Cluster Level）</td><td>命名空间级别（Namespace Level）</td></tr></tbody></table>',7)])])}const _=e(r,[["render",s]]);export{m as __pageData,_ as default};
